  7в†’import { RecordId } from "surrealdb";
  8в†’import { entityPrecisionScorer } from "./scorers/entity-precision";
  9в†’import { entityRecallScorer } from "./scorers/entity-recall";
 10в†’import { noPhantomPersonsScorer } from "./scorers/no-phantom-persons";
 11в†’import { evidenceGroundedScorer } from "./scorers/evidence-grounded";
 12в†’import { noExtraEntitiesScorer } from "./scorers/no-extra-entities";
 13в†’import { noContextBleedScorer } from "./scorers/no-context-bleed";
 14в†’import { evidenceSourceCurrentMessageScorer } from "./scorers/evidence-source-current-message";
 15в†’import { resolvedFromLineageScorer } from "./scorers/resolved-from-lineage";
 16в†’import { toolFilteringScorer } from "./scorers/tool-filtering";
 17в†’import { forbiddenKindsScorer } from "./scorers/forbidden-kinds";
 18в†’import { relationRecallScorer } from "./scorers/relation-recall";
 19в†’import { categoryAccuracyScorer } from "./scorers/category-accuracy";
 20в†’import type { ExtractionEvalOutput, GoldenCase, GoldenCaseIntent } from "./types";
 21в†’import { normalizeForSubstring } from "./scorers/shared";
 22в†’import { extractStructuredGraph } from "../app/src/server/extraction/extract-graph";
 23в†’import { persistExtractionOutput, appendExtractedTools } from "../app/src/server/extraction/persist-extraction";
 24в†’import { loadExtractionConversationContext, loadConversationGraphContext } from "../app/src/server/extraction/context-loaders";
 25в†’import type { SourceRecord } from "../app/src/server/extraction/types";
 26в†’import { loadWorkspaceProjects } from "../app/src/server/workspace/workspace-scope";
 27в†’import {
 28в†’  type EvalRuntime,
 29в†’  setupEvalRuntime,
 30в†’  teardownEvalRuntime,
 31в†’  seedWorkspace,
 32в†’  seedConversationContext,
 33в†’  seedUserMessage,
 34в†’  seedGraphEntities,
 35в†’  loadWorkspacePeopleCount,
 36в†’} from "./eval-test-kit";
 37в†’
 38в†’const extractionModel = process.env.EXTRACTION_MODEL ?? "anthropic/claude-3.5-haiku";
 39в†’const autoevalModel = requireEnv("AUTOEVAL_MODEL");
 40в†’
 41в†’const cacheDir = process.env.EVAL_CACHE_DIR ?? "eval-results/cache";
 42в†’const cachePath = join(cacheDir, "extraction-cache.json");
 43в†’const resultCache = loadCache(cachePath);
 44в†’const cases = JSON.parse(readFileSync(join(process.cwd(), "evals", "data", "golden-cases.json"), "utf8")) as GoldenCase[];
