 47в†’// strict_single is reserved for unambiguous one-entity probes.
 48в†’// Cases where multiple extractions are semantically valid should use multi_allowed.
 49в†’const intentScoreWeights: Record<
 50в†’  GoldenCaseIntent,
 51в†’  Record<
 52в†’    | "entity-precision"
 53в†’    | "entity-recall"
 54в†’    | "no-extra-entities"
 55в†’    | "no-phantom-persons"
 56в†’    | "evidence-grounded"
 57в†’    | "no-context-bleed"
 58в†’    | "evidence-source-current-message"
 59в†’    | "resolved-from-lineage"
 60в†’    | "tool-filtering"
 61в†’    | "forbidden-kinds"
 62в†’    | "factuality"
 63в†’    | "relation-recall"
 64в†’    | "category-accuracy",
 65в†’    number
