 72в†’    "no-phantom-persons": 0.12,
 73в†’    "evidence-grounded": 0.08,
 74в†’    "no-context-bleed": 0.05,
 75в†’    "evidence-source-current-message": 0.05,
 76в†’    "resolved-from-lineage": 0.04,
 77в†’    "tool-filtering": 0.06,
 78в†’    "forbidden-kinds": 0.08,
 79в†’    factuality: 0.02,
 80в†’    "relation-recall": 0,
 81в†’    "category-accuracy": 0.1,
 82в†’  },
 83в†’  multi_allowed: {
 84в†’    "entity-precision": 0.21,
 85в†’    "entity-recall": 0.21,
 86в†’    "no-extra-entities": 0.05,
 87в†’    "no-phantom-persons": 0.11,
 88в†’    "evidence-grounded": 0.08,
 89в†’    "no-context-bleed": 0.04,
 90в†’    "evidence-source-current-message": 0.06,
 91в†’    "resolved-from-lineage": 0.04,
 92в†’    "tool-filtering": 0.04,
 93в†’    "forbidden-kinds": 0.06,
 94в†’    factuality: 0.02,
 95в†’    "relation-recall": 0.03,
 96в†’    "category-accuracy": 0.1,
 97в†’  },
