110в†’const factualityScorer = createScorer<GoldenCase, ExtractionEvalOutput, GoldenCase>({
111в†’  name: "factuality",
112в†’  description: "Average factual grounding score for extracted entity texts against matched provenance evidence snippets.",
113в†’  scorer: async ({ input, output }) => {
114в†’    if (output.extractedEntities.length === 0) {
115в†’      return { score: 1 };
116в†’    }
117в†’
118в†’    let total = 0;
119в†’    for (const entity of output.extractedEntities) {
120в†’      const snippet = resolveEntityEvidenceSnippet(entity.text, output.evidenceRows, input.input);
121в†’      const result = await Factuality({
122в†’        input: snippet,
123в†’        output: entity.text,
124в†’        expected: snippet,
125в†’        model: autoevalModel,
126в†’      });
127в†’      total += result.score ?? 0;
128в†’    }
129в†’
130в†’    return { score: total / output.extractedEntities.length };
131в†’  },
132в†’});
