134в†’evalite<GoldenCase, ExtractionEvalOutput, GoldenCase>("Extraction Golden Cases", {
135в†’  data: cases.map((testCase) => ({ input: testCase, expected: testCase })),
136в†’  task: async (input) => runCase(input),
137в†’  scorers: [
138в†’    entityPrecisionScorer,
139в†’    entityRecallScorer,
140в†’    noExtraEntitiesScorer,
141в†’    noPhantomPersonsScorer,
142в†’    evidenceGroundedScorer,
143в†’    noContextBleedScorer,
144в†’    evidenceSourceCurrentMessageScorer,
145в†’    resolvedFromLineageScorer,
146в†’    toolFilteringScorer,
147в†’    forbiddenKindsScorer,
148в†’    relationRecallScorer,
149в†’    categoryAccuracyScorer,
150в†’    factualityScorer,
151в†’  ],
152в†’  columns: ({ input, output, scores }) => [
153в†’    { label: "Case", value: input.id },
154в†’    { label: "Intent", value: input.intent },
155в†’    { label: "Ent", value: `${output.extractedEntities.length}/${input.expectedEntities.length}` },
156в†’    { label: "Prec", value: formatScoreCell(scoreByName(scores, "entity-precision")) },
157в†’    { label: "Rec", value: formatScoreCell(scoreByName(scores, "entity-recall")) },
158в†’    { label: "Cat", value: formatScoreCell(scoreByName(scores, "category-accuracy")) },
159в†’    {
160в†’      label: "Avg",
161в†’      value: computeWeightedAverage(input.intent, scores).toFixed(2),
162в†’    },
163в†’  ],
164в†’});
