166в†’function scoreByName(
167в†’  scores: Array<{ name: string; score: number | null }>,
168в†’  name: string,
169в†’): number {
170в†’  const match = scores.find((score) => score.name === name);
171в†’  if (!match || match.score === null || Number.isNaN(match.score)) {
172в†’    throw new Error(`Missing score for scorer: ${name}`);
173в†’  }
174в†’
175в†’  return match.score;
176в†’}
177в†’
178в†’function formatScoreCell(value: number): string {
179в†’  return value.toFixed(2);
180в†’}
181в†’
182в†’function computeWeightedAverage(
183в†’  intent: GoldenCaseIntent,
184в†’  scores: Array<{ name: string; score: number | null }>,
185в†’): number {
186в†’  const weights = intentScoreWeights[intent];
187в†’  if (!weights) {
188в†’    throw new Error(`Unknown golden case intent: ${intent}`);
189в†’  }
190в†’
191в†’  let weightedTotal = 0;
192в†’  let weightTotal = 0;
193в†’  for (const [scorerName, weight] of Object.entries(weights)) {
194в†’    if (weight <= 0) {
195в†’      continue;
196в†’    }
197в†’
198в†’    weightedTotal += scoreByName(scores, scorerName) * weight;
199в†’    weightTotal += weight;
200в†’  }
201в†’
202в†’  if (weightTotal === 0) {
203в†’    throw new Error(`No scorer weights configured for intent: ${intent}`);
204в†’  }
205в†’
206в†’  return weightedTotal / weightTotal;
207в†’}
