209в†’function resolveEntityEvidenceSnippet(
210в†’  entityText: string,
211в†’  evidenceRows: Array<{ evidence?: string; fromText?: string; model?: string }>,
212в†’  fallbackInput: string,
213в†’): string {
214в†’  const normalizedEntityText = normalizeForSubstring(entityText);
215в†’  const matched = evidenceRows.find((row) => normalizeForSubstring(row.fromText ?? "") === normalizedEntityText);
216в†’  const snippet = matched?.evidence ?? evidenceRows[0]?.evidence ?? fallbackInput;
217в†’  return snippet.trim().length > 0 ? snippet : fallbackInput;
218в†’}
