220в†’async function runCase(testCase: GoldenCase): Promise<ExtractionEvalOutput> {
221в†’  const cacheKey = buildCaseCacheKey(extractionModel, testCase);
222в†’  const cached = resultCache[cacheKey];
223в†’  if (cached) {
224в†’    return {
225в†’      ...cached,
226в†’      extractedTools: cached.extractedTools ?? [],
227в†’      extractedRelations: cached.extractedRelations ?? [],
228в†’    };
229в†’  }
230в†’
231в†’  const { workspaceRecord, workspaceName, projectRecord, conversationRecord, ownerPersonCount } = await seedWorkspace(runtime.surreal, testCase.workspace_name);
232в†’  const conversationId = conversationRecord.id as string;
233в†’  const seededContext = testCase.context ?? [];
234в†’  const contextMessageIds = seededContext.length > 0
235в†’    ? await seedConversationContext(runtime.surreal, conversationRecord, seededContext)
236в†’    : [];
237в†’
238в†’  if (testCase.workspace_seed && testCase.workspace_seed.length > 0) {
239в†’    await seedGraphEntities(runtime.surreal, workspaceRecord, projectRecord, conversationRecord, testCase.workspace_seed);
240в†’  }
241в†’
242в†’  const userMessageRecord = await seedUserMessage(runtime.surreal, conversationRecord, testCase.input);
243в†’
244в†’  const extractionConversationContext = await loadExtractionConversationContext({
245в†’    surreal: runtime.surreal,
246в†’    conversationId,
247в†’    currentMessageRecord: userMessageRecord,
248в†’  });
249в†’  const extractionGraphContext = await loadConversationGraphContext(runtime.surreal, conversationId, 60);
250в†’  const workspaceProjects = await loadWorkspaceProjects(runtime.surreal, workspaceRecord);
251в†’  const workspaceProjectNames = workspaceProjects.map((project) => project.name);
252в†’
253в†’  const extraction = await extractStructuredGraph({
254в†’    extractionModel: runtime.extractionModel,
255в†’    conversationHistory: extractionConversationContext.conversationHistory,
256в†’    currentMessage: extractionConversationContext.currentMessage,
257в†’    graphContext: extractionGraphContext,
258в†’    sourceText: testCase.input,
259в†’    onboarding: true,
260в†’    workspaceName,
261в†’    projectNames: workspaceProjectNames,
262в†’  });
263в†’
264в†’  const now = new Date();
265в†’  const persistence = await persistExtractionOutput({
266в†’    surreal: runtime.surreal,
267в†’    embeddingModel: runtime.embeddingModel,
268в†’    embeddingDimension: runtime.config.embeddingDimension,
269в†’    extractionModelId: runtime.config.extractionModelId,
270в†’    extractionStoreThreshold: runtime.config.extractionStoreThreshold,
271в†’    workspaceRecord,
272в†’    sourceRecord: userMessageRecord as SourceRecord,
273в†’    sourceKind: "message",
274в†’    sourceLabel: testCase.input.slice(0, 140),
275в†’    promptText: testCase.input,
276в†’    output: extraction,
277в†’    sourceMessageRecord: userMessageRecord,
278в†’    extractionHistoryMessageIds: extractionConversationContext.conversationHistory.map(
279в†’      (row) => row.id.id as string,
280в†’    ),
281в†’    now,
282в†’  });
283в†’
284в†’  await appendExtractedTools(runtime.surreal, workspaceRecord, persistence.tools, now);
285в†’
286в†’  const [evidenceRows] = await runtime.surreal
287в†’    .query<[Array<{
288в†’      evidence?: string;
289в†’      from_text?: string;
290в†’      model?: string;
291в†’      evidence_source?: RecordId<"message", string>;
292в†’      resolved_from?: RecordId<"message", string>;
293в†’    }>]>(
294в†’      "SELECT evidence, from_text, model, evidence_source, resolved_from FROM extraction_relation WHERE `in` = $source;",
295в†’      { source: userMessageRecord },
296в†’    )
297в†’    .collect<[Array<{
298в†’      evidence?: string;
299в†’      from_text?: string;
300в†’      model?: string;
301в†’      evidence_source?: RecordId<"message", string>;
302в†’      resolved_from?: RecordId<"message", string>;
303в†’    }>]>();
304в†’
305в†’  const personCount = await loadWorkspacePeopleCount(runtime.surreal, workspaceRecord);
306в†’  const [workspaceToolRows] = await runtime.surreal
307в†’    .query<[Array<{ tools?: string[] }>]>("SELECT tools FROM $workspace LIMIT 1;", {
308в†’      workspace: workspaceRecord,
309в†’    })
310в†’    .collect<[Array<{ tools?: string[] }>]>();
311в†’  const extractedTools = workspaceToolRows[0]?.tools ?? [];
312в†’
313в†’  const [relationRows] = await runtime.surreal
314в†’    .query<[Array<{
315в†’      kind: string;
316в†’      in: { tb: string };
317в†’      out: { tb: string };
318в†’      from_text: string;
319в†’      to_text: string;
320в†’      confidence: number;
321в†’    }>]>(
322в†’      "SELECT kind, `in`, out, from_text, to_text, confidence FROM entity_relation WHERE source_message = $source AND kind != 'POSSIBLE_DUPLICATE';",
323в†’      { source: userMessageRecord },
324в†’    )
325в†’    .collect<[Array<{
326в†’      kind: string;
327в†’      in: { tb: string };
328в†’      out: { tb: string };
329в†’      from_text: string;
330в†’      to_text: string;
331в†’      confidence: number;
332в†’    }>]>();
333в†’
334в†’  const output: ExtractionEvalOutput = {
335в†’    caseId: testCase.id,
336в†’    input: testCase.input,
337в†’    userMessageId: userMessageRecord.id as string,
338в†’    contextMessageIds,
339в†’    extractedEntities: persistence.entities.map((e) => ({
340в†’      kind: e.kind,
341в†’      text: e.text,
342в†’      confidence: e.confidence,
343в†’      ...(e.category ? { category: e.category } : {}),
344в†’    })),
345в†’    extractedTools,
346в†’    personCount,
347в†’    ownerPersonCount,
348в†’    evidenceRows: evidenceRows.map((row) => ({
349в†’      evidence: row.evidence,
350в†’      fromText: row.from_text,
351в†’      model: row.model,
352в†’      evidenceSourceId: row.evidence_source?.id as string | undefined,
353в†’      resolvedFromId: row.resolved_from?.id as string | undefined,
354в†’    })),
355в†’    extractedRelations: relationRows.map((row) => ({
356в†’      kind: row.kind,
357в†’      fromKind: row.in.tb,
358в†’      fromText: row.from_text,
359в†’      toKind: row.out.tb,
360в†’      toText: row.to_text,
361в†’      confidence: row.confidence,
362в†’    })),
363в†’  };
364в†’
365в†’  resultCache[cacheKey] = output;
366в†’  saveCache(cachePath, resultCache);
367в†’  return output;
368в†’}
369в†’
370в†’function loadCache(path: string): Record<string, ExtractionEvalOutput> {
371в†’  if (!existsSync(path)) {
372в†’    return {};
373в†’  }
374в†’
375в†’  return JSON.parse(readFileSync(path, "utf8")) as Record<string, ExtractionEvalOutput>;
376в†’}
377в†’
378в†’function saveCache(path: string, cache: Record<string, ExtractionEvalOutput>): void {
379в†’  mkdirSync(cacheDir, { recursive: true });
380в†’  writeFileSync(path, JSON.stringify(cache, null, 2));
381в†’}
382в†’
383в†’function assertAutoevalEnv(): void {
384в†’  const hasOpenAiKey = hasEnv("OPENAI_API_KEY");
385в†’  const hasBraintrustKey = hasEnv("BRAINTRUST_API_KEY");
386в†’  if (!hasOpenAiKey && !hasBraintrustKey) {
387в†’    throw new Error(
388в†’      "Missing evaluator credentials. Set OPENAI_API_KEY (recommended for OPENAI_BASE_URL/OpenRouter) or BRAINTRUST_API_KEY.",
389в†’    );
390в†’  }
391в†’
392в†’  if (!hasEnv("OPENAI_BASE_URL")) {
393в†’    throw new Error("Missing OPENAI_BASE_URL for autoevals provider routing.");
394в†’  }
395в†’}
396в†’
397в†’function requireEnv(name: string): string {
398в†’  const value = process.env[name];
399в†’  if (!value || value.trim().length === 0) {
400в†’    throw new Error(`Missing required environment variable: ${name}`);
401в†’  }
402в†’  return value;
403в†’}
404в†’
405в†’function hasEnv(name: string): boolean {
406в†’  const value = process.env[name];
407в†’  return value !== undefined && value.trim().length > 0;
408в†’}
409в†’
410в†’function buildCaseCacheKey(modelId: string, testCase: GoldenCase): string {
411в†’  const cacheVersion = "classification-v3";
412в†’  const caseHash = createHash("sha256").update(JSON.stringify(testCase)).digest("hex").slice(0, 24);
413в†’  return `${cacheVersion}:${modelId}:${testCase.id}:${caseHash}`;
414в†’}
