251в†’function buildSeedEntityContent(kind: string, text: string, now: Date): Record<string, unknown> {
252в†’  const base = { created_at: now, updated_at: now };
253в†’  if (kind === "project") return { ...base, name: text, status: "active" };
254в†’  if (kind === "feature") return { ...base, name: text, status: "active" };
255в†’  if (kind === "task") return { ...base, title: text, status: "open" };
256в†’  if (kind === "decision") return { ...base, summary: text, status: "extracted" };
257в†’  return { ...base, text, status: "open" };
258в†’}
