201в†’export async function seedGraphEntities(
202в†’  surreal: Surreal,
203в†’  workspaceRecord: RecordId<"workspace", string>,
204в†’  projectRecord: RecordId<"project", string>,
205в†’  conversationRecord: RecordId<"conversation", string>,
206в†’  seeds: WorkspaceSeedItem[],
207в†’): Promise<void> {
208в†’  const now = new Date();
209в†’  const seedMessageRecord = new RecordId("message", randomUUID());
210в†’  await surreal.create(seedMessageRecord).content({
211в†’    conversation: conversationRecord,
212в†’    role: "assistant",
213в†’    text: "Workspace seed context.",
214в†’    createdAt: new Date(now.getTime() - 60_000),
215в†’  });
216в†’
217в†’  for (const seed of seeds) {
218в†’    const entityRecord = new RecordId(seed.kind, randomUUID());
219в†’    await surreal.create(entityRecord).content(buildSeedEntityContent(seed.kind, seed.text, now));
220в†’
221в†’    await surreal.relate(seedMessageRecord, new RecordId("extraction_relation", randomUUID()), entityRecord, {
222в†’      confidence: 0.95,
223в†’      extracted_at: now,
224в†’      created_at: now,
225в†’      model: "seed",
226в†’      from_text: seed.text,
227в†’      evidence: seed.text,
228в†’      evidence_source: seedMessageRecord,
229в†’    }).output("after");
230в†’
231в†’    if (seed.kind === "feature") {
232в†’      await surreal.relate(projectRecord, new RecordId("has_feature", randomUUID()), entityRecord as RecordId<"feature", string>, {
233в†’        added_at: now,
234в†’      }).output("after");
235в†’    }
236в†’
237в†’    if (seed.kind === "task" || seed.kind === "decision" || seed.kind === "question") {
238в†’      await surreal.relate(entityRecord, new RecordId("belongs_to", randomUUID()), projectRecord, {
239в†’        added_at: now,
240в†’      }).output("after");
241в†’    }
242в†’
243в†’    if (seed.kind === "project") {
244в†’      await surreal.relate(workspaceRecord, new RecordId("has_project", randomUUID()), entityRecord as RecordId<"project", string>, {
245в†’        added_at: now,
246в†’      }).output("after");
247в†’    }
248в†’  }
249в†’}
