260в†’export function createEventCollector(): SseRegistry & { getEvents(messageId: string): StreamEvent[] } {
261в†’  const events = new Map<string, StreamEvent[]>();
262в†’  return {
263в†’    registerMessage(messageId: string) {
264в†’      events.set(messageId, []);
265в†’    },
266в†’    handleStreamRequest(_messageId: string): Response {
267в†’      throw new Error("handleStreamRequest not available in eval mode");
268в†’    },
269в†’    emitEvent(messageId: string, event: StreamEvent) {
270в†’      events.get(messageId)?.push(event);
271в†’    },
272в†’    getEvents(messageId: string): StreamEvent[] {
273в†’      return events.get(messageId) ?? [];
274в†’    },
275в†’  };
276в†’}
