 2в†’
 3в†’function normalize(value: string): string {
 4в†’  return value
 5в†’    .toLowerCase()
 6в†’    .replace(/[^a-z0-9\s]/g, " ")
 7в†’    .replace(/\s+/g, " ")
 8в†’    .trim();
 9в†’}
10в†’
11в†’function tokenize(value: string): string[] {
12в†’  return normalize(value)
13в†’    .split(" ")
14в†’    .filter((token) => token.length > 0);
15в†’}
16в†’
17в†’export function nameSimilarity(a: string, b: string): number {
18в†’  const normalizedA = normalize(a);
19в†’  const normalizedB = normalize(b);
20в†’  const aTokens = new Set(tokenize(normalizedA));
21в†’  const bTokens = new Set(tokenize(normalizedB));
22в†’
23в†’  if (normalizedA.length === 0 || normalizedB.length === 0 || aTokens.size === 0 || bTokens.size === 0) {
24в†’    return 0;
25в†’  }
26в†’
27в†’  const overlap = [...aTokens].filter((token) => bTokens.has(token)).length;
28в†’  const minSize = Math.min(aTokens.size, bTokens.size);
29в†’  const union = new Set([...aTokens, ...bTokens]).size;
30в†’  const jaccard = overlap / union;
31в†’  const overlapRatio = overlap / minSize;
32в†’  const substringBonus = normalizedA.includes(normalizedB) || normalizedB.includes(normalizedA) ? 0.2 : 0;
33в†’  const exactBonus = normalizedA === normalizedB ? 0.2 : 0;
34в†’
35в†’  return Math.min(1, Math.max(jaccard, overlapRatio * 0.85) + substringBonus + exactBonus);
36в†’}
37в†’
38в†’export function isEntityNameMatch(a: string, b: string, threshold = 0.5): boolean {
39в†’  return nameSimilarity(a, b) >= threshold;
40в†’}
41в†’
42в†’export function normalizeForSubstring(value: string): string {
43в†’  return normalize(value);
44в†’}
45в†’
46в†’export function matchesExpectedEntity(
47в†’  expectedEntity: ExpectedEntity,
48в†’  extractedEntity: { kind: string; text: string },
49в†’  threshold = 0.5,
50в†’): boolean {
51в†’  if (expectedEntity.kind !== extractedEntity.kind) {
52в†’    return false;
53в†’  }
54в†’
55в†’  if ("text_contains" in expectedEntity) {
56в†’    const expectedSubstring = normalizeForSubstring(expectedEntity.text_contains);
57в†’    if (expectedSubstring.length === 0) {
58в†’      return false;
59в†’    }
60в†’
61в†’    return normalizeForSubstring(extractedEntity.text).includes(expectedSubstring);
62в†’  }
63в†’
64в†’  return isEntityNameMatch(expectedEntity.text, extractedEntity.text, threshold);
65в†’}
